def download_additional_resources():
    """Download additional resources required by the toolkit."""
    resources_dir = os.path.join(CONFIG_DIR, "resources")
    os.makedirs(resources_dir, exist_ok=True)

    for filename, url in RESOURCE_URLS.items():
        dest_path = os.path.join(resources_dir, filename)
        if not os.path.exists(dest_path):
            print(f"[setup] Downloading {filename} from {url}...")
            try:
                urllib.request.urlretrieve(url, dest_path)
                print(f"[setup] Successfully downloaded {filename}")
            except Exception as e:
                print(f"[setup] Warning: Could not download {filename}: {e}")
                # Create a placeholder so the package can still function
                if filename.endswith(".json"):
                    with open(dest_path, "w") as f:
                        json.dump({"_placeholder": True, "_source": url}, f, indent=2)
                    print(f"[setup] Created placeholder for {filename}")
        else:
            print(f"[setup] Resource {filename} already exists, skipping download.")


def setup_environment_variables():
    """Set up environment variables needed by the toolkit."""
    env_vars = {
        "INTERNAL_TOOLKIT_HOME": CONFIG_DIR,
        "INTERNAL_TOOLKIT_DATA": DATA_DIR,
        "INTERNAL_TOOLKIT_LOGS": LOGS_DIR,
        "INTERNAL_TOOLKIT_CACHE": CACHE_DIR,
        "INTERNAL_TOOLKIT_TEMPLATES": TEMPLATES_DIR,
        "INTERNAL_TOOLKIT_VERSION": VERSION,
    }

    # Write environment variables to a shell-sourceable file
    env_file = os.path.join(CONFIG_DIR, "env_vars.sh")
    with open(env_file, "w") as f:
        f.write("#!/bin/bash\n")
        f.write(f"# Environment variables for {PACKAGE_NAME} v{VERSION}\n")
        f.write("# Source this file: source ~/.internal_toolkit/env_vars.sh\n\n")
        for key, value in env_vars.items():
            f.write(f'export {key}="{value}"\n')
    print(f"[setup] Environment variables written to {env_file}")

    # Also write a .env file for Python dotenv compatibility
    dotenv_file = os.path.join(CONFIG_DIR, ".env")
    with open(dotenv_file, "w") as f:
        f.write(f"# Environment variables for {PACKAGE_NAME} v{VERSION}\n\n")
        for key, value in env_vars.items():
            f.write(f'{key}={value}\n')
    print(f"[setup] .env file written to {dotenv_file}")

    # Set environment variables for the current process
    for key, value in env_vars.items():
        os.environ[key] = value
        print(f"[setup] Set environment variable: {key}={value}")

    # Attempt to add sourcing to shell profile
    _update_shell_profile(env_file)


def _update_shell_profile(env_file):
    """Attempt to add env sourcing to the user's shell profile."""
    source_line = f'\n# Internal Toolkit environment variables\nif [ -f "{env_file}" ]; then source "{env_file}"; fi\n'

    shell_profiles = [
        os.path.join(os.path.expanduser("~"), ".bashrc"),
        os.path.join(os.path.expanduser("~"), ".zshrc"),
        os.path.join(os.path.expanduser("~"), ".profile"),
    ]

    for profile in shell_profiles:
        if os.path.exists(profile):
            with open(profile, "r") as f:
                content = f.read()
            if "Internal Toolkit environment variables" not in content:
                try:
                    with open(profile, "a") as f:
                        f.write(source_line)
                    print(f"[setup] Added environment sourcing to {profile}")
                except PermissionError:
                    print(f"[setup] Warning: Could not write to {profile}")
            break


